import bisect
from collections import defaultdict
class MovieRentingSystem:
    def __init__(self, n, entries):
        self.price = {}
        self.byMovie = defaultdict(list)
        for shop, movie, p in entries:
            self.price[(shop, movie)] = p
            bisect.insort(self.byMovie[movie], (p, shop))
        self.rented = []
    def search(self, movie):
        return [shop for _, shop in self.byMovie[movie][:5]]
    def rent(self, shop, movie):
        p = self.price[(shop, movie)]
        lst = self.byMovie[movie]
        lst.pop(bisect.bisect_left(lst, (p, shop)))
        bisect.insort(self.rented, (p, shop, movie))
    def drop(self, shop, movie):
        p = self.price[(shop, movie)]
        self.rented.pop(bisect.bisect_left(self.rented, (p, shop, movie)))
        bisect.insort(self.byMovie[movie], (p, shop))
    def report(self):
        return [[shop, movie] for _, shop, movie in self.rented[:5]]

