function bisect(arr, x) {
    let lo = 0, hi = arr.length;
    while (lo < hi) {
        const mid = (lo + hi) >> 1;
        if (cmp(arr[mid], x) < 0) lo = mid + 1; else hi = mid;
    }
    return lo;
}
function cmp(a, b) {
    const n = Math.min(a.length, b.length);
    for (let i = 0; i < n; i++) if (a[i] !== b[i]) return a[i] - b[i];
    return a.length - b.length;
}
function insort(arr, x) {
    arr.splice(bisect(arr, x), 0, x);
}
var MovieRentingSystem = function(n, entries) {
    this.price = new Map();
    this.byMovie = new Map();
    for (const [shop, movie, p] of entries) {
        this.price.set(shop + ',' + movie, p);
        if (!this.byMovie.has(movie)) this.byMovie.set(movie, []);
        insort(this.byMovie.get(movie), [p, shop]);
    }
    this.rented = [];
};
MovieRentingSystem.prototype.search = function(movie) {
    const lst = this.byMovie.get(movie) || [];
    return lst.slice(0, 5).map(e => e[1]);
};
MovieRentingSystem.prototype.rent = function(shop, movie) {
    const p = this.price.get(shop + ',' + movie);
    const lst = this.byMovie.get(movie);
    lst.splice(bisect(lst, [p, shop]), 1);
    insort(this.rented, [p, shop, movie]);
};
MovieRentingSystem.prototype.drop = function(shop, movie) {
    const p = this.price.get(shop + ',' + movie);
    this.rented.splice(bisect(this.rented, [p, shop, movie]), 1);
    insort(this.byMovie.get(movie), [p, shop]);
};
MovieRentingSystem.prototype.report = function() {
    return this.rented.slice(0, 5).map(e => [e[1], e[2]]);
};
